def solution(n: int = 1000) -> int:
    f1, f2 = 1, 1
    index = 2
    # Check if the current term (f2) has the required number of digits
    while len(str(f2)) < n:
        f1, f2 = f2, f1 + f2
        index += 1
    return index


if __name__ == "__main__":
    print(solution(1000))
